import { createContext, useState, useEffect } from 'react'

const CrmContext = createContext(null)

/**
 * Proveedor del contexto CRM.
 * En producción, accede a window["setClientApiContext"]().
 * Permite inyectar un mock via prop `xrmOverride` para tests/dev.
 *
 * @param {{ children: React.ReactNode, xrmOverride?: Object }} props
 */
export const CrmProvider = ({ children, xrmOverride = null }) => {
  const [xrm, setXrm] = useState(xrmOverride)

  useEffect(() => {
    if (xrmOverride) {
      setXrm(xrmOverride)
      return
    }
    try {
      const context = window['setClientApiContext']()
      setXrm(context)
    } catch {
      console.warn('[CrmProvider] No se pudo obtener el contexto Xrm de Power Platform.')
    }
  }, [xrmOverride])

  return <CrmContext.Provider value={xrm}>{children}</CrmContext.Provider>
}

export { CrmContext }
